&lt;<span style="color:#8b008b;font-weight:bold">table</span>&gt;
&lt;<span style="color:#8b008b;font-weight:bold">tr</span>&gt;&lt;<span style="color:#8b008b;font-weight:bold">td</span>&gt;用户ID&lt;/<span style="color:#8b008b;font-weight:bold">td</span>&gt;&lt;<span style="color:#8b008b;font-weight:bold">td</span>&gt;用户名称&lt;/<span style="color:#8b008b;font-weight:bold">td</span>&gt;&lt;/<span style="color:#8b008b;font-weight:bold">tr</span>&gt;
&lt;<span style="color:#8b008b;font-weight:bold">s:iterator</span> <span style="color:#658b00">value</span>=<span style="color:#cd5555">&#34;#session[&#34;</span><span style="color:#658b00">subMsg</span><span style="color:#a61717;background-color:#e3d2d2">&#34;]&#34;</span>&gt;
&lt;<span style="color:#8b008b;font-weight:bold">tr</span>&gt;&lt;<span style="color:#8b008b;font-weight:bold">td</span>&gt;&lt;<span style="color:#8b008b;font-weight:bold">s:property</span> <span style="color:#658b00">value</span>=<span style="color:#cd5555">&#34;id&#34;</span>/&gt;&lt;/<span style="color:#8b008b;font-weight:bold">td</span>&gt;&lt;<span style="color:#8b008b;font-weight:bold">td</span>&gt;&lt;<span style="color:#8b008b;font-weight:bold">s:property</span> <span style="color:#658b00">value</span>=<span style="color:#cd5555">&#34;name&#34;</span>/&gt;&lt;/<span style="color:#8b008b;font-weight:bold">td</span>&gt;&lt;/<span style="color:#8b008b;font-weight:bold">tr</span>&gt;
&lt;/<span style="color:#8b008b;font-weight:bold">s:iterator</span>&gt;
&lt;/<span style="color:#8b008b;font-weight:bold">table</span>&gt;
&lt;<span style="color:#8b008b;font-weight:bold">s:if</span> <span style="color:#658b00">test</span>=<span style="color:#cd5555">&#34;#session[&#34;</span><span style="color:#658b00">pageCount</span><span style="color:#a61717;background-color:#e3d2d2">&#34;]!=</span><span style="color:#658b00">null</span><span style="color:#a61717;background-color:#e3d2d2">&#34;</span>&gt;
&lt;<span style="color:#8b008b;font-weight:bold">s:iterator</span> <span style="color:#658b00">var</span>=<span style="color:#cd5555">&#34;i&#34;</span> <span style="color:#658b00">begin</span>=<span style="color:#cd5555">&#34;0&#34;</span> <span style="color:#658b00">end</span>=<span style="color:#cd5555">&#34;#session[&#34;</span><span style="color:#658b00">pageCount</span><span style="color:#a61717;background-color:#e3d2d2">&#34;]&#34;</span> <span style="color:#658b00">step</span>=<span style="color:#cd5555">&#34;1&#34;</span>&gt;
&lt;<span style="color:#8b008b;font-weight:bold">a</span> <span style="color:#658b00">href</span>=<span style="color:#cd5555">&#34;http://wewoor.blog.163.com/blog/hirb/nextPage?start=&lt;s:property value=&#34;</span><span style="color:#a61717;background-color:#e3d2d2">#</span><span style="color:#658b00">i</span><span style="color:#a61717;background-color:#e3d2d2">*</span><span style="color:#658b00">5</span><span style="color:#a61717;background-color:#e3d2d2">&#34;</span>/&gt;&#34;&gt;
